select 
from sys_permission


        and (permission_code like concat('%', #{keyword}, '%')
        or permission_name like concat('%', #{keyword}, '%')
        or api_path like concat('%', #{keyword}, '%'))


        and parent_id = #{parentId}


        and permission_type = #{permissionType}


        and status = #{status}


order by sort_num asc, id desc

